tool_input.old_string:
toggleSci() {
  const panel = document.getElementById('sci-panel');
  const panel2 = document.getElementById('sci-panel-2');
  const btn = document.getElementById('btn-sci');
  const label = document.getElementById('angle-unit-label');
  const isHidden = panel.hidden;
  panel.hidden = !isHidden;
  panel2.hidden = !isHidden;
  label.style.display = isHidden ? 'block' : 'none';
  if (isHidden) label.textContent = this.angleUnit;
  btn.textContent = isHidden ? '[basic]' : '[sci]';
},

tool_input.new_string:
toggleSci() {
  const panel = document.getElementById('sci-panel');
  const btn = document.getElementById('btn-sci');
  panel.hidden = !panel.hidden;
  btn.textContent = panel.hidden ? '[sci]' : '[basic]';
},

tool_input.old_string:
toggleAngleUnit() {
  const cycle = { RAD: 'GON', GON: 'DEG', DEG: 'RAD' };
  this.angleUnit = cycle[this.angleUnit];
  document.getElementById('angle-unit-label').textContent = this.angleUnit;
  document.querySelector('#sci-panel-2 button:last-child').textContent = this.angleUnit;
},

tool_input.new_string:
toggleAngleUnit() {
  const cycle = { RAD: 'GON', GON: 'DEG', DEG: 'RAD' };
  this.angleUnit = cycle[this.angleUnit];
  document.getElementById('btn-angle-unit').textContent = this.angleUnit;
},
